INSERT INTO chunks (document_id, tenant_id, content, chunk_index, token_count)
VALUES (
  '{{ $json.document_id }}',
  '{{ $json.tenant_id }}',
  {{ $json.content.includes("'") ? "$$" + $json.content + "$$" : "'" + $json.content + "'" }},
  {{ $json.chunk_index }},
  {{ $json.token_count }}
)
RETURNING id;

